function UserSettings({ user }) {
  const [name, setName] = useState(user.name);
  const [email, setEmail] = useState(user.email);
  const [notifications, setNotifications] = useState(user.preferences.notifications);

  const handleSave = async () => {
    // PROBLEM: Sending save request even if no fields changed
    // This wastes server processing and network energy.
    // Should check if (name !== user.name || email !== user.email ...)

    const payload = { name, email, preferences: { notifications } };

    try {
        await api.patch(`/users/${user.id}`, payload);
        alert('Saved!');
    } catch (err) {
        console.error(err);
    }
  };

  return (
    <div>
      <input value={name} onChange={e => setName(e.target.value)} />
      <input value={email} onChange={e => setEmail(e.target.value)} />
      <button onClick={handleSave}>Save</button>
    </div>
  );
}

