function ImageGallery({ images }) {
  // Render a grid of images for the portfolio
  if (!images || images.length === 0) return <div>No images</div>;

  return (
    <div className="gallery">
      {images.map(img => (
        <div key={img.id} className="img-container">
          {/* PROBLEM: Eager loading all images */}
          {/* If there are 100 images, all will download on load, wasting bandwidth */}
          {/* Should add loading="lazy" attribute to <img> tag */}
          <img 
            src={img.url} 
            alt={img.caption} 
            width={300} 
            height={200}
            className="gallery-img"
          />
          <p>{img.caption}</p>
        </div>
      ))}
    </div>
  );
}

function deleteComment(commentId) {
    // User clicked delete button on a comment
    if (!confirm('Are you sure?')) return;

    // Call API to delete
    fetch(`/api/comments/${commentId}`, { method: 'DELETE' })
        .then((resp) => {
           if (resp.ok) {
               // PROBLEM: Reloading the entire page to reflect removal
               // This re-downloads all assets and HTML.
               // Should just remove the DOM element or update React state.
               console.log('Reloading page...');
               window.location.reload();
           }
        });
}

